const item = $input.first();
const raw = item.json;

let js = '';
if (typeof raw === 'string') js = raw;
else if (raw.body) js = String(raw.body);
else if (raw.data) js = String(raw.data);
else js = JSON.stringify(raw).substring(0, 50000);

// Look for REST API patterns
const apiPatterns = [];

// Common REST endpoint patterns
const patterns = [
  /["'`](/[a-zA-Z0-9/_-]{5,80}processos?[a-zA-Z0-9/_-]{0,50})["'`]/g,
  /["'`](/api/[a-zA-Z0-9/_-]{3,80})["'`]/g,
  /["'`](/seam/resource[a-zA-Z0-9/_-]{0,80})["'`]/g,
  /["'`](/pje[a-zA-Z0-9/_-]{3,80})["'`]/g,
  /["'`](/rest/[a-zA-Z0-9/_-]{3,80})["'`]/g,
  /["'`](/services/[a-zA-Z0-9/_-]{3,80})["'`]/g,
];

const foundPaths = new Set();
for (const pattern of patterns) {
  let match;
  while ((match = pattern.exec(js)) !== null) {
    foundPaths.add(match[1]);
    if (foundPaths.size > 100) break;
  }
}

// Also look for "partes", "polo", "consulta" in context
const contextPatterns = [];
const ctxRegex = /(partes|polo.{0,20}ativo|polo.{0,20}passivo|numeroProcesso|consulta.{0,20}public).{0,200}/gi;
let ctxMatch;
let count = 0;
while ((ctxMatch = ctxRegex.exec(js)) !== null && count < 20) {
  contextPatterns.push(ctxMatch[0].substring(0, 150));
  count++;
}

return [{
  json: {
    js_size_chars: js.length,
    api_paths_found: Array.from(foundPaths).slice(0, 50),
    api_paths_count: foundPaths.size,
    partes_context: contextPatterns,
    js_sample_start: js.substring(0, 500),
  }
}];
